   119→func NewExternalAlertmanagerSender(l log.Logger, reg prometheus.Registerer, opts ...Option) (*ExternalAlertmanager, error) {
   120→	sdCtx, sdCancel := context.WithCancel(context.Background())
   121→
   122→	options := &ExternalAMOptions{
   123→		Options: Options{
   124→			QueueCapacity:   defaultMaxQueueCapacity,
   125→			MaxBatchSize:    DefaultMaxBatchSize,
   126→			Registerer:      reg,
   127→			DrainOnShutdown: defaultDrainOnShutdown,
   128→		},
   129→	}
   130→
   131→	for _, opt := range opts {
   132→		opt(options)
   133→	}
   134→
   135→	s := &ExternalAlertmanager{
   136→		logger:   l,
   137→		sdCancel: sdCancel,
   138→		options:  options,
   139→	}
   140→
   141→	if options.sanitizeLabelSetFn == nil {
   142→		options.sanitizeLabelSetFn = s.sanitizeLabelSet
   143→	}
   144→
   145→	s.manager = NewManager(
   146→		// Injecting a new registry here means these metrics are not exported.
   147→		// Once we fix the individual Alertmanager metrics we should fix this scenario too.
   148→		&options.Options,
   149→		toSlogLogger(s.logger),
   150→	)
   151→	sdMetrics, err := discovery.CreateAndRegisterSDMetrics(prometheus.NewRegistry())
   152→	if err != nil {
   153→		s.logger.Error("failed to register service discovery metrics", "error", err)
   154→		return nil, err
   155→	}
   156→	// Convert s.Logger to slog.Logger using the adapter
   157→	slogLogger := toSlogLogger(s.logger)
   158→	s.sdManager = discovery.NewManager(sdCtx, slogLogger, prometheus.NewRegistry(), sdMetrics)
   159→
   160→	if s.sdManager == nil {
   161→		return nil, errors.New("failed to create new discovery manager")
   162→	}
   163→
   164→	return s, nil
   165→}
   166→
   167→// ApplyConfig syncs a configuration with the sender.
   168→func (s *ExternalAlertmanager) ApplyConfig(orgId, id int64, alertmanagers []ExternalAMcfg) error {
   169→	notifierCfg, headers, err := buildNotifierConfig(alertmanagers)
   170→	if err != nil {
   171→		return err
   172→	}
   173→
   174→	s.logger = s.logger.New("org", orgId, "cfg", id)
   175→
   176→	s.logger.Info("Synchronizing config with external Alertmanager group")
   177→	if err := s.manager.ApplyConfig(notifierCfg, headers); err != nil {
   178→		return err
   179→	}
   180→
   181→	sdCfgs := make(map[string]discovery.Configs)
   182→	for k, v := range notifierCfg.AlertingConfig.AlertmanagerConfigs.ToMap() {
   183→		sdCfgs[k] = v.ServiceDiscoveryConfigs
   184→	}
   185→
   186→	return s.sdManager.ApplyConfig(sdCfgs)
   187→}
