   189→func (s *ExternalAlertmanager) Run() {
   190→	logger := s.logger
   191→	s.wg.Add(2)
   192→
   193→	go func() {
   194→		logger.Info("Initiating communication with a group of external Alertmanagers")
   195→
   196→		if err := s.sdManager.Run(); err != nil {
   197→			logger.Error("Failed to start the sender service discovery manager", "error", err)
   198→		}
   199→		s.wg.Done()
   200→	}()
   201→
   202→	go func() {
   203→		s.manager.Run(s.sdManager.SyncCh())
   204→		s.wg.Done()
   205→	}()
   206→}
