   307→func (s *ExternalAlertmanager) alertToNotifierAlert(alert models.PostableAlert) *Alert {
   308→	// Prometheus alertmanager has stricter rules for annotations/labels than grafana's internal alertmanager, so we sanitize invalid keys.
   309→	return &Alert{
   310→		Labels:       s.options.sanitizeLabelSetFn(alert.Labels),
   311→		Annotations:  s.options.sanitizeLabelSetFn(alert.Annotations),
   312→		StartsAt:     time.Time(alert.StartsAt),
   313→		EndsAt:       time.Time(alert.EndsAt),
   314→		GeneratorURL: alert.GeneratorURL.String(),
   315→	}
   316→}
   317→
   318→// sanitizeLabelSet sanitizes all given LabelSet keys according to sanitizeLabelName.
   319→// If there is a collision as a result of sanitization, a short (6 char) md5 hash of the original key will be added as a suffix.
   320→func (s *ExternalAlertmanager) sanitizeLabelSet(lbls models.LabelSet) labels.Labels {
   321→	ls := make(labels.Labels, 0, len(lbls))
   322→	set := make(map[string]struct{})
   323→
   324→	// Must sanitize labels in order otherwise resulting label set can be inconsistent when there are collisions.
   325→	for _, k := range sortedKeys(lbls) {
   326→		sanitizedLabelName, err := s.sanitizeLabelName(k)
   327→		if err != nil {
   328→			s.logger.Error("Alert sending to external Alertmanager(s) contains an invalid label/annotation name that failed to sanitize, skipping", "name", k, "error", err)
   329→			continue
   330→		}
   331→
   332→		// There can be label name collisions after we sanitize. We check for this and attempt to make the name unique again using a short hash of the original name.
   333→		if _, ok := set[sanitizedLabelName]; ok {
   334→			sanitizedLabelName = sanitizedLabelName + fmt.Sprintf("_%.3x", md5.Sum([]byte(k)))
   335→			s.logger.Warn("Alert contains duplicate label/annotation name after sanitization, appending unique suffix", "name", k, "newName", sanitizedLabelName, "error", err)
   336→		}
   337→
   338→		set[sanitizedLabelName] = struct{}{}
   339→		ls = append(ls, labels.Label{Name: sanitizedLabelName, Value: lbls[k]})
   340→	}
   341→
   342→	return ls
   343→}
   344→
   345→// sanitizeLabelName will fix a given label name so that it is compatible with prometheus alertmanager character restrictions.
   346→// Prometheus alertmanager requires labels to match ^[a-zA-Z_][a-zA-Z0-9_]*$.
   347→// Characters with an ASCII code < 127 will be replaced with an underscore (_), characters with ASCII code >= 127 will be replaced by their hex representation.
   348→// For backwards compatibility, whitespace will be removed instead of replaced with an underscore.
   349→func (s *ExternalAlertmanager) sanitizeLabelName(name string) (string, error) {
   350→	if len(name) == 0 {
   351→		return "", errors.New("label name cannot be empty")
   352→	}
   353→
   354→	if isValidLabelName(name) {
   355→		return name, nil
   356→	}
   357→
   358→	s.logger.Warn("Alert sending to external Alertmanager(s) contains label/annotation name with invalid characters", "name", name)
   359→
   360→	// Remove spaces. We do this instead of replacing with underscore for backwards compatibility as this existed before the rest of this function.
   361→	sanitized := strings.Join(strings.Fields(name), "")
   362→
   363→	// Replace other invalid characters.
   364→	var buf strings.Builder
   365→	for i, b := range sanitized {
   366→		if isValidCharacter(i, b) {
   367→			buf.WriteRune(b)
   368→			continue
   369→		}
   370→
   371→		if b <= unicode.MaxASCII {
   372→			buf.WriteRune('_')
   373→			continue
   374→		}
   375→
   376→		if i == 0 {
   377→			buf.WriteRune('_')
   378→		}
   379→		_, _ = fmt.Fprintf(&buf, "%#x", b)
   380→	}
